          "collectionName": "AOSA Volume 1",
          "title": "VisTrails",
          "author": "Juliana Freire, David Koop, Emanuele Santos, Carlos Scheidegger, Claudio Silva, and Huy T. Vo",
          "url": "https://aosabook.org/en/v1/vistrails.html",
